To create a MongoDB Vector Search index for a collection using the
[MongoDB Node driver](node/fundamentals/indexes)
v6.6.0 or later, perform the following steps:

```javascript
const { MongoClient } = require("mongodb");

// connect to your deployment
const uri =  "<connectionString>";

const client = new MongoClient(uri);

async function run() {
   try {
     const database = client.db("<databaseName>");
     const collection = database.collection("<collectionName>");

     // define your MongoDB Vector Search index
     const index = {
         name: "<indexName>",
         type: "vectorSearch",
         definition: {
           "fields": [
             {
               "type": "vector",
               "numDimensions": <numberOfDimensions>,
               "path": "<fieldToIndex>",
               "similarity": "euclidean | cosine | dotProduct"
             },
             {
               "type": "filter",
               "path": "<fieldToIndex>"
             },
             ...
           ]
         }
     }

     // run the helper method
     const result = await collection.createSearchIndex(index);
     console.log(`New search index named ${result} is building.`);
     // wait for the index to be ready to query
     console.log("Polling to check if the index is ready. This may take up to a minute.")
     let isQueryable = false;
     while (!isQueryable) {
       const cursor = collection.listSearchIndexes();
       for await (const index of cursor) {
         if (index.name === result) {
           if (index.queryable) {
             console.log(`${result} is ready for querying.`);
             isQueryable = true;
           } else {
             await new Promise(resolve => setTimeout(resolve, 5000));
           }
         }
       }
     }
   } finally {
     await client.close();
   }
}
run().catch(console.dir);

```

> **Example:** Create a file named `vector-index.js`.

| \<connectionString>   | Cluster connection string. To learn more, see Connect to a Cluster via Client Libraries.      |
| --------------------- | --------------------------------------------------------------------------------------------- |
| \<databaseName>       | Database that contains the collection for which you want to create the index.                 |
| \<collectionName>     | Collection for which you want to create the index.                                            |
| \<indexName>          | Name of your index. If you omit the index name, defaults to vector\_index.                    |
| \<numberOfDimensions> | Number of vector dimensions that MongoDB Vector Search enforces at index-time and query-time. |
| \<fieldToIndex>       | Vector and filter fields to index.                                                            |

> **Example:** Copy and paste the following into the `vector-index.js` file
> and replace the `<connectionString>` placeholder value. The
> following index definition indexes the
> `plot_embedding_voyage_3_large` field as the `vector` type
> and the `genres` and `year` fields as the `filter` type
> in a MongoDB Vector Search index. The `plot_embedding_voyage_3_large`
> field contains embeddings created using Voyage AI's
> `voyage-3-large` embedding model. The index definition
> specifies `2048` vector dimensions and measures similarity
> using `dotProduct` function.
>
> Basic Example
>
> The following index definition indexes only the vector
> embeddings field (`plot_embedding_voyage_3_large`) for
> performing vector search.
